 28	
 29	type ReduxStateProps = {
 30	  externalServices: ExternalServiceInfo[];
 31	  navCollapsed: boolean;
 32	  tracingUrl?: string;
 33	};
 34	
 35	type ReduxDispatchProps = {
 36	  setNavCollapsed: (collapse: boolean) => void;
 37	};
 38	
 39	type NavigationProps = ReduxStateProps & ReduxDispatchProps;
 40	
 41	export const MASTHEAD_HEIGHT = '76px';
 42	
 43	const flexBoxColumnStyle = kialiStyle({
 44	  display: 'flex',
 45	  flexDirection: 'column'
 46	});
 47	
 48	export const NavigationComponent: React.FC<NavigationProps> = (props: NavigationProps) => {
 49	  const [isMobileView, setIsMobileView] = React.useState<boolean>(false);
 50	  const [isNavOpenDesktop, setIsNavOpenDesktop] = React.useState<boolean>(true);
 51	  const [isNavOpenMobile, setIsNavOpenMobile] = React.useState<boolean>(false);
 52	
 53	  const { pathname } = useLocation();
 54	
 55	  React.useEffect((): void => {
 56	    let pageTitle = serverConfig.installationTag ?? 'Kiali';
 57	
 58	    if (homeCluster?.name) {
 59	      pageTitle += ` [${homeCluster?.name}]`;
 60	    }
 61	
 62	    document.title = pageTitle;
 63	  }, []);
 64	
 65	  const isGraph = (): boolean => {
 66	    return pathname.startsWith('/graph') || pathname.startsWith('/mesh');
 67	  };
 68	
 69	  const onNavToggleDesktop = (): void => {
 70	    setIsNavOpenDesktop(!isNavOpenDesktop);
 71	    props.setNavCollapsed(!props.navCollapsed);
 72	  };
 73	
 74	  const onNavToggleMobile = (): void => {
 75	    setIsNavOpenMobile(!isNavOpenMobile);
 76	  };
 77	
 78	  const onPageResize = ({ mobileView, windowSize }: { mobileView: boolean; windowSize: number }): void => {
 79	    let ismobile = mobileView;
 80	
 81	    if (windowSize < 1000) {
 82	      ismobile = true;
 83	    }
 84	
 85	    setIsMobileView(ismobile);
 86	  };
 87	
 88	  const isNavOpen = isMobileView ? isNavOpenMobile : isNavOpenDesktop || !props.navCollapsed;
 89	
 90	  const masthead = (
 91	    <Masthead role="kiali_header" style={{ height: MASTHEAD_HEIGHT }}>
 92	      <MastheadToggle>
 93	        <PageToggleButton
 94	          variant={ButtonVariant.plain}
 95	          aria-label="Kiali navigation"
 96	          isSidebarOpen={isNavOpen}
 97	          onSidebarToggle={isMobileView ? onNavToggleMobile : onNavToggleDesktop}
 98	        >
 99	          <BarsIcon />
100	        </PageToggleButton>
101	      </MastheadToggle>
102	      <MastheadMain>
103	        <MastheadBrand component={props => <Link {...props} to="#" />}>
104	          <img src={kialiLogoDark} alt="Kiali Logo" />
105	        </MastheadBrand>
106	      </MastheadMain>
107	      <MastheadContent style={{ height: MASTHEAD_HEIGHT }}>
108	        <MastheadItems />
109	      </MastheadContent>
110	    </Masthead>
111	  );
112	
113	  const menu = <Menu isNavOpen={isNavOpen} externalServices={props.externalServices} />;
114	
115	  const Sidebar = (
116	    <PageSidebar style={{ width: '210px' }} isSidebarOpen={isNavOpen}>
117	      <PageSidebarBody>{menu}</PageSidebarBody>
118	    </PageSidebar>
119	  );
120	
121	  return (
122	    <Page
123	      header={masthead}
124	      sidebar={Sidebar}
125	      onPageResize={(_, { mobileView, windowSize }) => onPageResize({ mobileView, windowSize })}
126	    >
127	      <MessageCenter drawerTitle="Message Center" />
128	      <PageSection className={flexBoxColumnStyle} variant="light">
129	        <RenderPage isGraph={isGraph()} />
130	      </PageSection>
131	    </Page>
132	  );
133	};
134	
135	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
136	  navCollapsed: state.userSettings.interface.navCollapse,
137	  tracingUrl: state.tracingState.info && state.tracingState.info.url ? state.tracingState.info.url : undefined,
138	  externalServices: state.statusState.externalServices
139	});
140	
141	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
142	  setNavCollapsed: (collapse: boolean) => dispatch(UserSettingsThunkActions.setNavCollapsed(collapse))
143	});
144	
145	export const Navigation = connect(mapStateToProps, mapDispatchToProps)(NavigationComponent);

